def _normalize_path(path: str) -> str:
    if not path:
        return "/"
    if path.startswith("/static/"):
        return "/static/*"
    parts = [p for p in path.split("/") if p]
    norm = []
    for p in parts:
        if p.isdigit():
            norm.append(":id")
        elif len(p) > 32 and all(c.isalnum() or c in "-_" for c in p):
            norm.append(":token")
        else:
            norm.append(p)
    return "/" + "/".join(norm)


def _get_registry() -> Optional[CollectorRegistry]:
    prom_multiproc_dir = os.environ.get("PROMETHEUS_MULTIPROC_DIR")
    if prom_multiproc_dir:
        registry = CollectorRegistry()
        multiprocess.MultiProcessCollector(registry)
        return registry
    return None


def create_app() -> Flask:
    app = Flask(__name__)

    version = os.getenv("APP_VERSION", "unknown")
    APP_INFO.labels(service=SERVICE, env=ENV, hostname=HOSTNAME, version=version).set(1)

